import{_ as i,o as a,c as t,ag as e}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"协作工具与平台","description":"","frontmatter":{},"headers":[],"relativePath":"zh/tools/collaboration.md","filePath":"zh/tools/collaboration.md"}'),r={name:"zh/tools/collaboration.md"};function o(s,l,n,h,u,d){return a(),t("div",null,[...l[0]||(l[0]=[e('<h1 id="协作工具与平台" tabindex="-1">协作工具与平台 <a class="header-anchor" href="#协作工具与平台" aria-label="Permalink to &quot;协作工具与平台&quot;">​</a></h1><h2 id="有效的团队沟通" tabindex="-1">有效的团队沟通 <a class="header-anchor" href="#有效的团队沟通" aria-label="Permalink to &quot;有效的团队沟通&quot;">​</a></h2><p>DevOps 的成功取决于打破团队之间的壁垒。现代协作工具实现了实时沟通、透明度和知识共享。</p><h2 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h2><p>团队协作和通信的领先平台，已成为 DevOps 工作流的核心。</p><h3 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h3><p><strong>频道</strong></p><ul><li>公共频道用于团队可见性</li><li>私有频道用于敏感讨论</li><li>基于主题的组织（#deployments、#incidents、#releases）</li></ul><p><strong>直接消息</strong></p><ul><li>一对一的对话</li><li>专注讨论的群组消息</li></ul><p><strong>集成</strong></p><ul><li>CI/CD 管道通知</li><li>监控告警和值班轮换</li><li>GitHub/GitLab 活动源</li><li>事故管理系统</li></ul><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h3><ol><li><strong>频道命名</strong>：使用清晰、描述性的名称（#prod-incidents、#eng-discussion）</li><li><strong>线程</strong>：使用线程保持对话组织有序</li><li><strong>自动化</strong>：集成告警和通知</li><li><strong>存档策略</strong>：维护可搜索的对话历史</li><li><strong>值班集成</strong>：将关键告警路由到值班频道</li></ol><h2 id="github-issues-和讨论" tabindex="-1">GitHub Issues 和讨论 <a class="header-anchor" href="#github-issues-和讨论" aria-label="Permalink to &quot;GitHub Issues 和讨论&quot;">​</a></h2><h3 id="github-issues" tabindex="-1">GitHub Issues <a class="header-anchor" href="#github-issues" aria-label="Permalink to &quot;GitHub Issues&quot;">​</a></h3><ul><li>追踪 bug、特性和任务</li><li>链接到拉取请求和提交</li><li>分配团队成员</li><li>使用标签分类</li><li>里程碑追踪发布</li></ul><h3 id="github-讨论" tabindex="-1">GitHub 讨论 <a class="header-anchor" href="#github-讨论" aria-label="Permalink to &quot;GitHub 讨论&quot;">​</a></h3><ul><li>RFC（征求意见）讨论</li><li>架构决策</li><li>Q&amp;A 论坛</li><li>知识库文章</li></ul><h2 id="项目板" tabindex="-1">项目板 <a class="header-anchor" href="#项目板" aria-label="Permalink to &quot;项目板&quot;">​</a></h2><p>使用项目板可视化跨团队的工作：</p><h3 id="看板板" tabindex="-1">看板板 <a class="header-anchor" href="#看板板" aria-label="Permalink to &quot;看板板&quot;">​</a></h3><ul><li>待办、进行中、审查、完成列</li><li>拖放问题管理</li><li>自动化工作流</li></ul><h3 id="规划功能" tabindex="-1">规划功能 <a class="header-anchor" href="#规划功能" aria-label="Permalink to &quot;规划功能&quot;">​</a></h3><ul><li>预估工作量</li><li>设置优先级</li><li>分配到冲刺或里程碑</li><li>跟踪进度</li></ul><h2 id="文档实践" tabindex="-1">文档实践 <a class="header-anchor" href="#文档实践" aria-label="Permalink to &quot;文档实践&quot;">​</a></h2><h3 id="文档位置" tabindex="-1">文档位置 <a class="header-anchor" href="#文档位置" aria-label="Permalink to &quot;文档位置&quot;">​</a></h3><p><strong>README.md</strong></p><ul><li>快速入门指南</li><li>项目概述</li><li>设置说明</li></ul><p><strong>Wiki 或知识库</strong></p><ul><li>架构决策</li><li>常见任务的运行手册</li><li>事故事后分析</li><li>团队程序</li></ul><p><strong>代码注释</strong></p><ul><li>解释&quot;为什么&quot;，而不是&quot;什么&quot;</li><li>记录复杂算法</li><li>链接到相关 issue/PR</li></ul><h3 id="活的文档" tabindex="-1">活的文档 <a class="header-anchor" href="#活的文档" aria-label="Permalink to &quot;活的文档&quot;">​</a></h3><ul><li>将文档保存在代码仓库中</li><li>与代码更改一起审查文档</li><li>使用文档作为测试（例如代码示例）</li><li>与发布一起版本化文档</li></ul><h2 id="事故管理" tabindex="-1">事故管理 <a class="header-anchor" href="#事故管理" aria-label="Permalink to &quot;事故管理&quot;">​</a></h2><h3 id="事故沟通" tabindex="-1">事故沟通 <a class="header-anchor" href="#事故沟通" aria-label="Permalink to &quot;事故沟通&quot;">​</a></h3><ol><li><strong>检测</strong>：自动化告警触发事故响应</li><li><strong>通知值班</strong>：通过 Slack/PagerDuty 通知相关团队</li><li><strong>声明事故</strong>：发布到 #incidents 频道</li><li><strong>状态更新</strong>：在事故线程中定期更新</li><li><strong>解决</strong>：清除事故并开始事后分析</li></ol><h3 id="事后审查" tabindex="-1">事后审查 <a class="header-anchor" href="#事后审查" aria-label="Permalink to &quot;事后审查&quot;">​</a></h3><ul><li>无责任事后分析</li><li>根本原因分析</li><li>预防行动项目</li><li>在 wiki 中记录以供将来参考</li></ul><h2 id="知识共享" tabindex="-1">知识共享 <a class="header-anchor" href="#知识共享" aria-label="Permalink to &quot;知识共享&quot;">​</a></h2><h3 id="定期实践" tabindex="-1">定期实践 <a class="header-anchor" href="#定期实践" aria-label="Permalink to &quot;定期实践&quot;">​</a></h3><p><strong>工程站会</strong></p><ul><li>每日 15 分钟同步</li><li>阻碍和优先级</li><li>跨团队可见性</li></ul><p><strong>每周架构/DevOps 会议</strong></p><ul><li>设计审查</li><li>新工具评估</li><li>流程改进</li></ul><p><strong>季度学习会议</strong></p><ul><li>复杂系统的深入探讨</li><li>技术探索</li><li>嘉宾演讲</li></ul><p><strong>内部技术博客</strong></p><ul><li>分享学习和最佳实践</li><li>庆祝胜利</li><li>记录决策</li></ul><h2 id="指标和透明度" tabindex="-1">指标和透明度 <a class="header-anchor" href="#指标和透明度" aria-label="Permalink to &quot;指标和透明度&quot;">​</a></h2><h3 id="仪表板" tabindex="-1">仪表板 <a class="header-anchor" href="#仪表板" aria-label="Permalink to &quot;仪表板&quot;">​</a></h3><ul><li>部署频率</li><li>构建时间</li><li>错误率</li><li>值班告警数量</li><li>团队速度</li></ul><p>显示在共享空间（Slack、wiki）中以实现可见性和问责制。</p><h2 id="远程优先沟通" tabindex="-1">远程优先沟通 <a class="header-anchor" href="#远程优先沟通" aria-label="Permalink to &quot;远程优先沟通&quot;">​</a></h2><p>对于分布式团队：</p><ul><li>默认使用书面沟通</li><li>记录会议供异步消费</li><li>在共享空间中记录决策</li><li>使用时区感知的日程安排</li><li>提供多种贡献方式</li></ul>',57)])])}const g=i(r,[["render",o]]);export{b as __pageData,g as default};
